INSERT INTO public.photos VALUES (21430, 'Calle del Portillo 1918', 'Imagen de la nueva gran fachada principal del colegio e internado de las Escuelas Pâ”œÂ¡as de los padres escolapios (fundados en 1735), producto de la remodelaciâ”œâ”‚n acometida por Miguel â”œÃ¼ngel Navarro Pâ”œÂ®rez. Algunos de sus elementos serâ”œÃ­n modificados o suprimidos en una reforma posterior (1961). La calle Nueva del Portillo, tambiâ”œÂ®n se encuentra en obras de ampliaciâ”œâ”‚n y ensanchamiento. Fuente visual: postal de la serie "Colegio de las Escuelas Pâ”œÂ¡as" de Zaragoza, titulada "Fachada principal del Internado", editada por Fototipia Thomas (Barcelona), en www.ebay.es/', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65449100, -0.88515100, '0101000020E6100000BCB1A0302853ECBF5F43705CC6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34382016532.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34382016532.webp', 'https://www.flickr.com/photos/zaragozaantigua/34382016532/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
