INSERT INTO public.photos VALUES (21828, 'Gigantes y Cabezudos 1931', 'Imagen capturada desde cierta altura, posiblemente en el nâ”¬â•‘ 8 del Coso alto, de la comparsa de Gigantes y Cabezudos en un posado conjunto durante las fiestas mayores de Zaragoza, al que se suman gozosos pardales y tancredos conscientes del inmortal momento. Figuran las gigantonas representaciones del rey Alfonso I (antes, Jaime I) y Doâ”œâ–’a Urraca (antes, una de las mujeres de Jaime I), el Duque y la Duquesa de Villahermosa, el Chino y la Negra, Don Quijote y Dulcinea, y las de los mâ”œÃ­s menudos Tuerto, Verrugâ”œâ”‚n, Morico, Robaculeros, Boticario, Torero, Forana, y Forano. Tras ellos, el palacio de la Audiencia, y el arranque de la calle de Cerdâ”œÃ­n. Fuente visual: foto Marâ”œÂ¡n Chivite, en diario "Ahora".', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65412600, -0.88388300, '0101000020E610000018B14F00C548ECBF4DBB9866BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32680328502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32680328502.webp', 'https://www.flickr.com/photos/zaragozaantigua/32680328502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22103, 'Calle del General Franco 1951', 'La calle del General Franco, luego del Conde de Aranda, en la confluencia hacia la derecha con la calle de las Escuelas Pâ”œÂ¡as, en una vista centrada en el soleado tramo que comienza en el colegio de los Escolapios. Sobre la calzada se cruzan una unidad tranviaria de la lâ”œÂ¡nea 2. Madrid y una composiciâ”œâ”‚n motor+remolque de la lâ”œÂ¡nea 3. Delicias. Fuente visual: Los tranvâ”œÂ¡as de Zaragoza, Javier Peâ”œâ–’a Gonzalvo, Josâ”œÂ® Marâ”œÂ¡a Valero Suâ”œÃ­rez, Zaragoza: DPZ, 1985.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65422700, -0.88460400, '0101000020E610000024253D0CAD4EECBF8194D8B5BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20683173996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20683173996.webp', 'https://www.flickr.com/photos/zaragozaantigua/20683173996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
