INSERT INTO public.photos VALUES (22785, 'Calle del General Franco 1979', 'Imagen centrada en el tradicionalista râ”œâ”‚tulo de la calle del General Franco adosado a la fachada del colegio de los PP. Escolapios. Esta calle, antigua del Portillo, habâ”œÂ¡a sido redenominada del Conde de Aranda en los aâ”œâ–’os veinte del pasado siglo XX. En 1937 el Consistorio faccioso le cambiâ”œâ”‚ la denominaciâ”œâ”‚n por la de General Franco. En 1979, tras la recuperaciâ”œâ”‚n de la democracia municipal, el nuevo ayuntamiento con mayorâ”œÂ¡a de izquierdas (PSOE, PCE, PTA) decidiâ”œâ”‚ modificar del nombre de algunos de los 102 viales de la ciudad que tras el 17-18 de julio de 1936 habâ”œÂ¡an sido cambiados por el nuevo râ”œÂ®gimen. Asâ”œÂ¡, la calle del General Franco recuperâ”œâ”‚ su previa denominaciâ”œâ”‚n (Conde de Aranda), al igual que la calle del Requetâ”œÂ® Aragonâ”œÂ®s (5 de Marzo). En el caso de la plaza de Josâ”œÂ® Antonio tambiâ”œÂ®n estaba previsto que recuperara su denominaciâ”œâ”‚n anterior (Castelar), si bien finalmente se quedarâ”œÂ¡a con una nueva: Los Sitios. El paseo de Calvo Sotelo, que fuera Avenida de Pablo Iglesias, hubiera tenido que ser la Gran Vâ”œÂ¡a de la Constituciâ”œâ”‚n, y se quedâ”œâ”‚ en Gran Vâ”œÂ¡a a secas. A lo largo de ese aâ”œâ–’o de 1979 otros nombres se aâ”œâ–’adieron a la lista (Marina Moreno, General Millâ”œÃ­n Astray, General Mola, Requetâ”œÂ® Navarro, Vieja Guardia ...) En noviembre de 2017 aâ”œâ•‘n perduran en la ciudad algunos viales que homenajean a quienes se alzaron en armas contra la democracia espaâ”œâ–’ola republicana en 1936. Fuente visual: Andalâ”œÃ­n, periâ”œâ”‚dico semanal aragonâ”œÂ®s, 1979.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65439000, -0.88476300, '0101000020E610000044BFB67EFA4FECBF2B6A300DC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38413110772.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38413110772.webp', 'https://www.flickr.com/photos/zaragozaantigua/38413110772/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22791, 'Coso Alto 1978', 'Imagen capturada desde el despejado ensanche resultante del derribo de la manzana de viviendas entre las antiguas calles de las Escuelas Pâ”œÂ¡as y Cerdâ”œÃ­n, centrada en el emboque de la calle de Azoque, al fondo. Chaflanero, perduraba el edificio "La ciudad de Londres", diseâ”œâ–’ado por Albiâ”œâ–’ana, aunque los inmediatos andamios de derribo del nâ”¬â•‘ 6 anunciaban la pronta prolongaciâ”œâ”‚n quirâ”œâ•‘rgica de la Vâ”œÂ¡a Imperial por esa zona. Hacia la derecha, principio de la calle del General Franco. Hacia la izquierda, arranque del tramo alto del Coso. Tras el ingreso por la calle Azoque, perduraba la antigua plaza de Luis Santâ”œÃ­ngel, luego desaparecida. En primer plano, notable concentraciâ”œâ”‚n de vehâ”œÂ¡culos aparcados al raso. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65405700, -0.88405800, '0101000020E6100000A48CB800344AECBF255CC823B8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41192728892.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41192728892.webp', 'https://www.flickr.com/photos/zaragozaantigua/41192728892/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23047, 'Av. de Câ”œÂ®sar Augusto 1991', 'Imagen capturada posiblemente desde la altura del inmueble del nâ”¬â•‘ 42 de la avenida de Câ”œÂ®sar Augusto, y centrada en la nueva iluminaciâ”œâ”‚n nocturna mediante farolas "de corte antiguo" del tramo de esta vâ”œÂ¡a reciâ”œÂ®n remodelado con motivo de la construcciâ”œâ”‚n de un aparcamiento subterrâ”œÃ­neo con capacidad para 349 vehâ”œÂ¡culos, y cuya entrada y salida en esta escena todavâ”œÂ¡a estâ”œÃ­n cerradas con vallas de obra. El importe total de esta intervenciâ”œâ”‚n, unos 402 millones de pesetas, fue cubierto por la empresa Estacionamientos El Pilar, S.A. (EPSA), concesionaria de la explotaciâ”œâ”‚n comercial tanto de este aparcamiento como los de la plaza del Pilar y de los Juzgados, cuyas instalaciones pasarâ”œÃ­n a propiedad municipal en el aâ”œâ–’o 2041.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65439600, -0.88421700, '0101000020E6100000C4263273814BECBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50437258566.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50437258566.webp', 'https://www.flickr.com/photos/zaragozaantigua/50437258566/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23512, 'Coso Alto 1938', 'Otra de las interesantes imâ”œÃ­genes capturadas por un miembro de la "Legiâ”œâ”‚n Condor", el contingente de la Luftwaffe enviado para echar una mano a sus camaradas espaâ”œâ–’oles nacionalistas, durante su estancia en la ciudad a finales de los aâ”œâ–’os 30. La vista parece realizada desde la terraza del acuartelamiento de estos alemanes voladores (colegio de los Escolapios). Inmediata, la que fuera antigua plaza de Estrâ”œÂ®vedes, o confluencia de la Cedacerâ”œÂ¡a, Albarderâ”œÂ¡a, Azoque, y Coso. En la imagen, esas dos primeras calles eran ya (tiempo ha) Escuelas Pâ”œÂ¡as, y Cerdâ”œÃ­n, a la izquierda. A la derecha, primeros nâ”œâ•‘meros pares del Coso, con un pedazo del edificio "Ciudad de Londres", y la fachada de la "Farmacia Nueva" de Ramâ”œâ”‚n Puig, recayente a esta calle.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65410800, -0.88408800, '0101000020E61000004E27D9EA724AECBFA7069ACFB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24524440199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24524440199.webp', 'https://www.flickr.com/photos/zaragozaantigua/24524440199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23525, 'Calle de Cerdâ”œÃ­n 1932', 'Imagen capturada en el arranque del Coso Alto y centrada en la manzana de viviendas entre las calles de las Escuelas Pâ”œÂ¡as (a la izquierda) y la de Cerdâ”œÃ­n (a la derecha), en cuyo nâ”¬â•‘ 1 estaba radicado el Hotel Hispano Francâ”œÂ®s, y en sus bajos comerciales el almacâ”œÂ®n de comestibles de Emâ”œÂ®rito Gambâ”œâ”‚n.', 1932, 1932, 1932, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65430000, -0.88421700, '0101000020E6100000C4263273814BECBFEBE2361AC0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49918087943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49918087943.webp', 'https://www.flickr.com/photos/zaragozaantigua/49918087943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24076, 'Calle General Franco 1960', 'Imagen capturada en el interior del cinematâ”œâ”‚grafo Victoria tras la reforma proyectada por los arquitectos Josâ”œÂ® de Yarza Garcâ”œÂ¡a y Alejandro Allâ”œÃ­negui Fâ”œÂ®lez. Esta sala estuvo funcional como cine entre 1943 y 1985. Fuente visual: arch. J. de Yarza', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65422200, -0.88532000, '0101000020E6100000BFD4CF9B8A54ECBF6F29E78BBDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38216863761.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38216863761.webp', 'https://www.flickr.com/photos/zaragozaantigua/38216863761/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25152, 'Calle San Ildefonso aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, representando la calle de San Ildefonso, con la iglesia homâ”œâ”‚nima (luego de Santiago el Mayor) al fondo a la derecha. Fuente: Lâ”œÃ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65297400, -0.88497000, '0101000020E6100000A81DFE9AAC51ECBFB491EBA694D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627091013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627091013.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627091013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25700, 'Arco de San Ildefonso 1925', 'Imagen del Arco de San Ildefonso, capturado desde la calle de San Ildefonso. Pasado el arco, y a la derecha, se abre la plaza de San Lamberto. Al fondo, la calle de Diego Castillo conduce a la calle Ramâ”œâ”‚n y Cajal, y a la plaza de la Victoria. Este arco formaba parte del grandioso conjunto barroco del convento de San Ildefonso de los PP. Dominicos, construido entre 1625 y 1695. La enorme iglesia conventual estaba flanqueada por el arranque, sin culminar, de dos poderosas torres de planta cuadrangular. El acceso a la torre de la derecha se habâ”œÂ¡a horadado y convertido en arco de medio punto y bâ”œâ”‚veda de caâ”œâ–’â”œâ”‚n, para comunicaciâ”œâ”‚n viaria. Fuente visual: Lucien Roisin, AMZ.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65277100, -0.88499900, '0101000020E61000003BC43F6CE951ECBF7C6308008ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21370663624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21370663624.webp', 'https://www.flickr.com/photos/zaragozaantigua/21370663624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25815, 'Calle del General Franco c.1955', 'Tranvâ”œÂ¡a de la lâ”œÂ¡nea 5 "Venecia-Delicicas", frente al colegio de Escuelas Pâ”œÂ¡as. Fuente: www.facebook.com/photo.php?fbid=518027164989911&set=g...', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65410500, -0.88427800, '0101000020E61000002F505260014CECBF36936FB6B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14738231119.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14738231119.webp', 'https://www.flickr.com/photos/zaragozaantigua/14738231119/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25852, 'Calle del General Franco c.1956', 'Imagen capturada desde cierta altura y centrada en el primer tramo de los nâ”œâ•‘meros pares de la calle del General Franco, donde destaca la gran fachada del colegio de los Escolapios, de la que destacan las dos originales torrecillas que culminaban el ingreso principal al colegio, y el torreâ”œâ”‚n que albergâ”œâ”‚ un observatorio meteorolâ”œâ”‚gico. Una reforma posterior eliminarâ”œÂ¡a estos remates. En el centro de la animada escena callejera, una composiciâ”œâ”‚n tranviaria de la lâ”œÂ¡nea 5. Venecia-Delicias, posiblemente compuesta por el coche motor nâ”¬â•‘ 82 y el remolque nâ”¬â•‘ 78, encaminado hacia el Coso Alto. Otra composiciâ”œâ”‚n de esta lâ”œÂ¡nea, al fondo, se dirige hacia el barrio de Las Delicias.', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65430000, -0.88488200, '0101000020E6100000D6355A0EF450ECBFEBE2361AC0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49889078638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49889078638.webp', 'https://www.flickr.com/photos/zaragozaantigua/49889078638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21046, 'Calle de la Misericordia 1867', 'Dibujo incluido en el anteproyecto para la "Academia de Yngenieros del egercito", con detalle de la fachada principal del edificio recayente a la calle de la Misericordia, donde estuviera la antigua fâ”œÃ­brica de salitres vecina del cuartel de Convalecientes. Este proyecto no pasâ”œâ”‚ de las musas al teatro, y el solar de la antigua fâ”œÃ­brica de salitres fue incorporado al cuartel de Convalecientes, luego cuartel de ingenieros de Sangenâ”œÂ¡s.', 1867, 1867, 1867, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65334600, -0.88914100, '0101000020E61000002C0C91D3D773ECBF787C7BD7A0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54224330883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54224330883.webp', 'https://www.flickr.com/photos/zaragozaantigua/54224330883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21175, 'Cuartel de Sangenis c.1890', 'Formaciones de caballerâ”œÂ¡a en el patio del cuartel de Sangenis. Al fondo, la Torre Nueva, la de San Felipe, el convento de la Victoria, la câ”œâ•‘pula de la iglesia de la Manteria y las traseras de la iglesia de San Ildefonso. Fuente: cesbor.blogspot.com.es/', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65340700, -0.88843500, '0101000020E610000075E5B33C0F6EECBF1EFD2FD7A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31250452330.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31250452330.webp', 'https://www.flickr.com/photos/zaragozaantigua/31250452330/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21299, 'Cuartel de Sangenis 1903', 'Foto: Nâ”œâ•‘â”œâ–’ez. "Desfile del ganado y de la maniobra". Vista del patio del cuartel de Sangenis o de Pontoneros, con perspectiva al este de la câ”œâ•‘pula de la iglesia de la Manterâ”œÂ¡a, que se queda pequeâ”œâ–’ita al lado del gran volumen de la de San Ildefonso. A la izquierda, convento de los Mâ”œÂ¡nimos de la Victoria. Fuente visual: Revista La Ilustraciâ”œâ”‚n Espaâ”œâ–’ola y Americana.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65343100, -0.88796300, '0101000020E610000087DBA161316AECBFA69883A0A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32509288995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32509288995.webp', 'https://www.flickr.com/photos/zaragozaantigua/32509288995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21712, 'Convento de Santa Ana 1931', 'Casa-Noviciado de las Hermanas de la Caridad de Santa Ana, en 1931. Proyectado por Julio Bravo y Folch en 1905, se sitâ”œâ•‘a en la calle de la Madre Rafols 13 de Zaragoza. Fuente: La Hormiga de Oro, noviembre de 1931.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65329700, -0.88934600, '0101000020E610000062821ABE8575ECBF97C9703C9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18557530363.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18557530363.webp', 'https://www.flickr.com/photos/zaragozaantigua/18557530363/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23692, 'Avenida San Juan Bosco 1964', '1964. "Avda. S. Juan Bosco-Avda. Gâ”œâ”‚mez Laguna". Familiar posado en un entorno agreste, porque este tramo de San Juan Bosco (desde Franco y Lâ”œâ”‚pez) estaba aâ”œâ•‘n por definir. Este era uno de los muchos "aquâ”œÂ¡ se acaba la ciudad". Al fondo, la mole del Edificio Torresol. A la derecha, algunas parcelas, y el nuevo edificio de la Escuela de Magisterio, ademâ”œÃ­s de las enormes explanadas donde se instalaban las carpas de los circos y ferias en octubre. A la izquierda, tapando las parcelas de la Ciudad Jardâ”œÂ¡n, los recientes bloques de viviendas de la calle Milagrosa. Si el fotâ”œâ”‚grafo se hubiera dado la vuelta, hubiera sacado una interesante variedad de campos de cultivo que la ciudad estaba a punto de tragarse, y alguna parcela agrâ”œÂ¡cola por aâ”œâ–’adidura. Como no lo hizo, pues nada.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.64359800, -0.90478400, '0101000020E6100000C6353E93FDF3ECBFB0E2546B61D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14972351665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14972351665.webp', 'https://www.flickr.com/photos/zaragozaantigua/14972351665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21906, 'Cabalgata 1939', 'Imagen capturada durante la "cabalgata de los Reyes Magos" celebrada el 5 de enero de 1939, con salida en la plaza de Santo Domingo frente el Ayuntamiento y regreso al mismo punto tras un largo recorrido urbano donde en la plaza de Basilio Paraâ”œÂ¡so se les uniâ”œâ”‚ el "Mago Nicolâ”œÃ­s". En la imagen, la comitiva del rey Gaspar con sus pajes a caballo y criados a su servicio sale de los jardines del Hospicio Provincial entre los asilados del Hogar Pignatelli para seguir su itinerario por la calle de la Madre Rafols. En el pilar de la derecha, restos de un anuncio del "Aguinaldo del Combatiente", establecido en el territorio ocupado por el ejâ”œÂ®rcito nacionalista a fin de recaudar recursos econâ”œâ”‚micos para llevar a los soldados y milicias, tanto combatientes, como hospitalizados, "el recuerdo de esta cristiana y tradicional fiesta de Navidad" que "les envâ”œÂ¡an los verdaderos espaâ”œâ–’oles que con intensa emociâ”œâ”‚n admiran su comportamiento heroico y estâ”œÃ­n espiritualmente unidos con ellos en esta santa cruzada de la redenciâ”œâ”‚n de Espaâ”œâ–’a" (texto de la Orden publicada en el Boletâ”œÂ¡n Oficial del Estado el 9 de diciembre de 1936).', 1939, 1939, 1939, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65353900, -0.88974200, '0101000020E61000009015FC36C478ECBF8DD47B2AA7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51730770771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51730770771.webp', 'https://www.flickr.com/photos/zaragozaantigua/51730770771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22068, 'Iglesia de Santiago 1958', 'Iglesia de Santiago el Mayor. El mal estado permanente de la câ”œâ•‘pula obliga a una actuaciâ”œâ”‚n. El arquitecto Borobia sube a la câ”œâ•‘pula para inspeccionar personalmente su estado, en unos andamios instalados para la ocasiâ”œâ”‚n. Concluye que el estado es muy malo. Aâ”œâ–’os despuâ”œÂ®s, con proyecto y, con financiaciâ”œâ”‚n, la câ”œâ•‘pula es restaurada integralmente, dâ”œÃ­ndole su aspecto actual. Fuente visual: "Una mirada a travâ”œÂ®s de la arquitectura: Regino y Josâ”œÂ® Borobio Ojeda", Daniel Estabâ”œÂ®n Boldova, 2013.', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65279300, -0.88569900, '0101000020E61000006A32E36DA557ECBF640795B88ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15107841094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15107841094.webp', 'https://www.flickr.com/photos/zaragozaantigua/15107841094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22295, 'Câ”œâ•‘pula Santiago el Mayor 1965', 'Archivo Municipal. Gerardo Sancho. 13/07/1965 En el verano del aâ”œâ–’o 1860, un rayo produjo el hundimiento de la câ”œâ•‘pula de la iglesia de Santiago el Mayor. Al poco tiempo, se hizo otra, aunque de bastante menos calidad. Casi un siglo despuâ”œÂ®s, en 1958, Regino Borobio dirigiâ”œâ”‚ una intervenciâ”œâ”‚n de urgencia, dado su precario estado. En 1964 se iniciaron las obras para consolidar definitivamente la câ”œâ•‘pula, derribar del cupulâ”œÂ¡n existente y construir otro mâ”œÃ­s ligero, ademâ”œÃ­s de un arreglo general del techado. Estas obras duraron quince meses, fueron dirigidas tambiâ”œÂ®n por el arquitecto Regino Borobio, y le dieron su actual aspecto.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65279300, -0.88569900, '0101000020E61000006A32E36DA557ECBF640795B88ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15409523374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15409523374.webp', 'https://www.flickr.com/photos/zaragozaantigua/15409523374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22341, 'Calle Pignatelli 1961', 'Imagen de la calle Pignatelli a la altura de los antiguos nâ”œâ•‘meros 106-108 y 104. Al fondo, a la derecha, esta calle viene estrechica desde allâ”œÃ­ en Azoque, cuando en el siglo XVIII era una sucesiâ”œâ”‚n de calles denominadas ""Paja", "Dama", "Porterâ”œÂ¡a de las Victoria" (por el convento de ese nombre), "Cantarerâ”œÂ¡as", y "Eras del Campo del Toro", hasta llegar al Portillo. En el momento de capturar la imagen, desde la calle Mariano Cerezo, a la derecha, y hasta la plaza del Portillo, a la izquierda, habâ”œÂ¡a una continuidad determinada por la presencia, detrâ”œÃ­s de estos edificios, del castrense "Parque de Artillerâ”œÂ¡a". Justo a nuestras espaldas queda el Hogar Pignatelli. Mâ”œÃ­s tarde en el tiempo, cuando el "Parque de Artillerâ”œÂ¡a" sea comprado por el Ayuntamiento durante la "Operaciâ”œâ”‚n Cuarteles", se abrirâ”œÃ­ a la izquierda una continuidad de la calle Mayoral. En este punto concreto hoy estâ”œÃ­ la denominada "Glorieta de Josâ”œÂ® Aznâ”œÃ­rez". De los edificios de la imagen (actuales 98-100 de la calle), que fueran producto de una remodelaciâ”œâ”‚n llevada a cabo por Fernando de Yarza en 1902, hoy sâ”œâ”‚lo queda la fachada, el resto es obra moderna. El antiguo 104, con su fachada de ladrillo, ha desaparecido, subsumido. Los bajos comerciales siguen vacantes. Fuente visual: amable aportaciâ”œâ”‚n del Archivo personal de Pablo Valdâ”œÂ®s.', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65425200, -0.88966700, '0101000020E6100000E692AAED2678ECBFDAAB8F87BED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20093917226.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20093917226.webp', 'https://www.flickr.com/photos/zaragozaantigua/20093917226/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22619, 'Hospital Provincial 1971', 'Hospital de Nuestra Seâ”œâ–’ora de Gracia de Zaragoza, â”œâ”‚leo de Antonio Torres Clavero, 1971.', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65198200, -0.88671700, '0101000020E6100000D8D47954FC5FECBF53CA6B2574D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19374860350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19374860350.webp', 'https://www.flickr.com/photos/zaragozaantigua/19374860350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22659, 'Plaza de la Victoria 1970', 'Plaza de la Victoria en una escena capturada durante la tradicional celebraciâ”œâ”‚n de San Juan de Dios, patrono del Cuerpo de Bomberos desde 1953. En esta plaza y a la derecha estaba ubicado el municipal Parque de Bomberos habilitado desde 1907 en el antiguo convento de Nuestra Seâ”œâ–’ora de la Victoria de los Padres Mâ”œÂ¡nimos de San Francisco de Paula que, desamortizado en 1835, a finales de siglo fue reformado para dar cabida a un Parque de Bomberos y Depâ”œâ”‚sito Municipal, ademâ”œÃ­s de unas escuelas elementales de niâ”œâ–’os y niâ”œâ–’as, lo que supuso el derribo de la iglesia conventual. Al fondo y esquinera, junto a la banda de mâ”œâ•‘sica, clarea la entrada a Frutos Solâ”œÃ­ns, S.A., en el nâ”¬â•‘ 34 de la calle de Ramâ”œâ”‚n y Cajal, antigua fâ”œÃ­brica de camas de Froilâ”œÃ­n Solâ”œÃ­ns S.A. En primer tâ”œÂ®rmino, el alcalde Mariano Horno Liria pasa revista a la formaciâ”œâ”‚n de bomberos en uniforme de gala.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65372300, -0.88605100, '0101000020E6100000AFD172A0875AECBF4ED2FC31ADD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22274483284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22274483284.webp', 'https://www.flickr.com/photos/zaragozaantigua/22274483284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22876, 'Plaza San Lamberto 1987', 'Una mirada a la plaza de San Lamberto que, junto con las inmediatas calles de las Doncellas y del Caballo, se configuraba como un tradicional espacio pecaminoso de la ciudad definido y conocido por el ejercicio de la prostituciâ”œâ”‚n, ser zona de putas, o de mercadeo de carne humana y soberanâ”œÂ¡a de prostituidores. En los siglos XVI-XVII, el burdel o puterâ”œÂ¡a estuvo localizado muy cerca de aquâ”œÂ¡ y era pâ”œâ•‘blico porque dependâ”œÂ¡a de las ordenanzas municipales. En el siglo XVIII la prostituciâ”œâ”‚n fue consideraba un mal necesario, de ejercicio privado y oculto a la vista, y en el XIX fue reglamentada desde un punto de vista sanitario. En el siglo XX esta actividad se fue diversificando en algunas calles y zonas de la ciudad, incluso en una muy renombrada de la periferia. La de la imagen, capturada desde la altura de la torre norte de la iglesia de Santiago el Mayor sita sobre el Arco de San Ildefonso, perdura actualmente.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65304200, -0.88559000, '0101000020E6100000BB44F5D6C056ECBF0C7558E196D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15851642572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15851642572.webp', 'https://www.flickr.com/photos/zaragozaantigua/15851642572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22915, 'Calle de Pignatelli 1987', 'Imagen centrada en el nâ”œâ•‘mero 60 de la calle de Ramâ”œâ”‚n Pignatelli (antigua de Cantarerâ”œÂ¡as), edificio esquinero con la calle de Josâ”œÂ® Zamoray (antigua del Candil, a la derecha). Fuente visual: AMZ.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”œÃ´RICO', 41.65410200, -0.88744500, '0101000020E610000084F57F0EF365ECBFC51F459DB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25065776518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25065776518.webp', 'https://www.flickr.com/photos/zaragozaantigua/25065776518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23174, 'Convento de los Mâ”œÂ¡nimos 2004', 'Obras de rehabilitaciâ”œâ”‚n del antiguo convento franciscano de los Mâ”œÂ¡nimos de la Victoria (1576). Habâ”œÂ¡an comenzado en 1998 y se reanudaron en 2002 y 2004, proyectâ”œÃ­ndose abrir en 2007 como Museo del Fuego y de los Bomberos. Finalmente, la inauguraciâ”œâ”‚n se produjo en 2012. La imagen muestra el patio del complejo. Fuente: Ayuntamiento de Zaragoza.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65367700, -0.88672600, '0101000020E6100000A56950340F60ECBFDE921CB0ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33434444930.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33434444930.webp', 'https://www.flickr.com/photos/zaragozaantigua/33434444930/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23240, 'Arrabal islâ”œÃ­mico 2002', 'En 2001 se hallaron restos arqueolâ”œâ”‚gicos de un arrabal de Saraqusta de finales del siglo X-comienzos del XI, anterior a la conquista cristiana de la ciudad, en la zona del Campo del Toro protegida por la nueva muralla de rajola, posiblemente de funcionarios y trabajadores vinculados con el cercano palacio de la Aljaferâ”œÂ¡a. El hallazgo se realizâ”œâ”‚ en el solar que ocupaban el patio y las dependencias anejas al antiguo Cuartel de Sangenis de Pontoneros e Ingenieros, que quedaron en pie tras los derribos de los aâ”œâ–’os 80, como el edificio de viviendas para oficiales chaflanero con la calle Madre Rafols. En esta zona estaba previsto ubicar el Archivo Histâ”œâ”‚rico de la Corona de Aragâ”œâ”‚n, pues la titularidad del terreno habâ”œÂ¡a pasado a la DGA, mas los sondeos preceptivos para detectar posibles restos arqueolâ”œâ”‚gicos antes de acometer los trabajos de construcciâ”œâ”‚n del edificio del Archivo, dieron un imprevisto giro a las cosas. La incidencia de lo encontrado era tan elevada, que se desechâ”œâ”‚ compatibilizar ambos asuntos: los restos se cubrieron para su conservaciâ”œâ”‚n, el proyecto de Archivo se abandonâ”œâ”‚, y la parcela retornâ”œâ”‚ al Patrimonio municipal, sin adjudicarse nuevos usos. En el aâ”œâ–’o 2010 se realizâ”œâ”‚ un anteproyecto para la promociâ”œâ”‚n y gestiâ”œâ”‚n en esta zona de un edificio de alojamientos para la comunidad universitaria en el marco del Ã”Ã‡Â£Plan Aragonâ”œÂ®s para facilitar el acceso a la vivienda y rehabilitaciâ”œâ”‚n 2009-2012Ã”Ã‡Ã˜. En 2024 se terminaron las obras de la residencia de estudiantes, de capital privado, que incluyeron un anfiteatro sobre el lugar donde se hallan los restos arqueolâ”œâ”‚gicos. En la imagen, al fondo a la derecha, la plaza de Josâ”œÂ® Marâ”œÂ¡a Forquâ”œÂ®. A la izquierda, la calle de la Palma. A la derecha, fuera de plano, el antiguo edificio de viviendas militares de la calle Madre Rafols. Fuente: Zaragoza Vivienda.', 2002, 2002, 2002, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65351500, -0.88873300, '0101000020E6100000EE073C308070ECBF04392861A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19086318419.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19086318419.webp', 'https://www.flickr.com/photos/zaragozaantigua/19086318419/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23242, 'Calle de Escopeterâ”œÂ¡a 2008', 'En 2001 se hallaron restos arqueolâ”œâ”‚gicos de un arrabal de Saraqusta de finales del siglo X-comienzos del XI, anterior a la conquista cristiana de la ciudad, en la zona del Campo del Toro protegida por la nueva muralla de rajola, posiblemente de residencia de funcionarios y trabajadores vinculados con el cercano palacio de la Aljaferâ”œÂ¡a. El hallazgo se realizâ”œâ”‚ en el solar que ocupaban el patio y las dependencias anejas al antiguo cuartel de Sangenis de Pontoneros e Ingenieros, aâ”œâ•‘n en pie tras los derribos de los aâ”œâ–’os 80, como el edificio de viviendas para oficiales chaflanero con la calle de Madre Rafols. Aquâ”œÂ¡ estaba previsto ubicar el Archivo Histâ”œâ”‚rico de la Corona de Aragâ”œâ”‚n, pues la titularidad del terreno habâ”œÂ¡a pasado a la DGA, mas los sondeos arqueolâ”œâ”‚gicos preceptivos dieron un imprevisto giro a las cosas. La incidencia de lo encontrado era tan elevada, que se desechâ”œâ”‚ compatibilizar ambos asuntos: los restos se cubrieron para su conservaciâ”œâ”‚n, el proyecto de Archivo se abandonâ”œâ”‚, y la parcela retornâ”œâ”‚ al Patrimonio municipal, sin adjudicarse nuevos usos. En el aâ”œâ–’o 2010 se realizâ”œâ”‚ un anteproyecto para promover un edificio de alojamientos para la comunidad universitaria dentro del Ã”Ã‡Â£Plan Aragonâ”œÂ®s para facilitar el acceso a la vivienda y rehabilitaciâ”œâ”‚n 2009-2012Ã”Ã‡Ã˜. Desde entonces, silencio. No hay banda. Inmediato a este solar, otro terreno, de propiedad privada, esquinero entre Escopeterâ”œÂ¡a y plaza Josâ”œÂ® Marâ”œÂ¡a Forquâ”œÂ®, fue tambiâ”œÂ®n objeto de catas que sacaron a la luz otro buen pedazo del citado arrabal medieval. Como en el caso anterior, los particulares proyectos de construcciâ”œâ”‚n previstos quedaron encallados, y los restos arqueolâ”œâ”‚gicos de adobe y tapial, una vez finalizados los trabajos cientâ”œÂ¡ficos, quedaron joreâ”œÃ­ndose al aire. Inmediatamente comenzâ”œâ”‚ el natural proceso de colmataciâ”œâ”‚n, a largo plazo, y el humano, mucho mâ”œÃ­s acelerado y radical, consistente en la deposiciâ”œâ”‚n de multidisciplinares residuos sâ”œâ”‚lidos urbanos, orgâ”œÃ­nicos, e inorgâ”œÃ­nicos. Esto es lo que la imagen capt', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65378100, -0.88841000, '0101000020E61000003D0FEECEDA6DECBF83DF8618AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24493212850.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24493212850.webp', 'https://www.flickr.com/photos/zaragozaantigua/24493212850/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23935, 'Calle de la Misericordia c.1896', 'Imagen capturada en los patios del cuartel de Sangenis del arma de ingenieros-pontoneros sito en la calle de la Misericordia durante la formaciâ”œâ”‚n previa a la reglamentaria salida hacia una parada militar. Entre el material rodante destacan los componentes del moderno puente flotante danâ”œÂ®s o Andersen. Al fondo, a la izquierda, la gran câ”œâ•‘pula del antiguo convento de San Ildefonso. A la derecha, instalaciones del Hospital Provincial. Fuente visual: www.bne.es/', 1896, 1896, 1896, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65326800, -0.88822800, '0101000020E610000012876C205D6CECBFFCC22B499ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25810873298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25810873298.webp', 'https://www.flickr.com/photos/zaragozaantigua/25810873298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24232, 'Calle de Ramâ”œâ”‚n y Cajal 1955', 'Luminosa imagen de la local comparsa de cabezudos creada por Fâ”œÂ®lix Oroz capturada en el patio del antiguo Convento de Nuestra Seâ”œâ–’ora de la Victoria de los PP. Mâ”œÂ¡nimos de San Francisco de Paula, desde 1907 convertido en el Parque de Bomberos de la ciudad. De izquierda a derecha, los cabezudos Boticario, Torero, Tuerto, Morico, Forana, Forano, Robaculeros y Berrugâ”œâ”‚n. Fuente visual: postal Darvi, en www.todocoleccion.net', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65367700, -0.88672600, '0101000020E6100000A56950340F60ECBFDE921CB0ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28187959429.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28187959429.webp', 'https://www.flickr.com/photos/zaragozaantigua/28187959429/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24394, 'Ramâ”œâ”‚n y Cajal 2005', 'Imagen capturada durante la definitiva fase de rehabilitaciâ”œâ”‚n del antiguo Convento de Nuestra Seâ”œâ–’ora de la Victoria de los PP. Mâ”œÂ¡nimos de San Francisco de Paula como municipal Museo del Fuego y de los Bomberos. Esta obra fue comenzada en 1998 y quedâ”œâ”‚ parada poco despuâ”œÂ®s. En 2002 fue retomada y en 2003 quedâ”œâ”‚ de nuevo paralizada. Se retomaron los trabajos en octubre de 2004, con algunas modificaciones respecto al proyecto original, que fueron terminados a finales de 2007, con la idea de inaugurar el museo durante los fastos de la gran Exposiciâ”œâ”‚n del aâ”œâ–’o siguiente. Fue abierto al pâ”œâ•‘blico de forma efectiva en junio de 2012. A la izquierda de la imagen, los modernos bloques de viviendas correspondientes al nâ”¬â•‘ 36 de la calle de Ramâ”œâ”‚n y Cajal. Fuente visual: www.zaragoza.es/', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65343700, -0.88631800, '0101000020E61000006765FB90B75CECBF887FD8D2A3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26080451368.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26080451368.webp', 'https://www.flickr.com/photos/zaragozaantigua/26080451368/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24404, 'Convento de los Mâ”œÂ¡nimos 1875', 'En 1875, el arquitecto municipal Segundo Dâ”œÂ¡az realizâ”œâ”‚ el plano y perfiles del antiguo convento de los frailes Mâ”œÂ¡nimos de la Victoria, sito entre las calles de Pignatelli y del Hospital, al objeto de realizar modificaciones para su uso como Escuelas (luego Grupo Escolar Ramâ”œâ”‚n y Cajal, con escuela de niâ”œâ–’os, de niâ”œâ–’as, y de pâ”œÃ­rvulos) y Depâ”œâ”‚sito municipal. El dibujo representa, asâ”œÂ¡, el perfil con el estado del edificio en esa fecha: en el centro, el gran patio central que vertebraba las estancias del antiguo convento, y a la derecha, la gran iglesia y su destacada torre, de principios del siglo XVII. A la iglesia se accedâ”œÂ¡a por un ensanchamiento de la calle del Hospital al que dio nombre este convento: plaza de la Victoria. Fue desamortizado en 1835 y convertido en cuartel, y mâ”œÃ­s tarde en escuela municipal. Durante unas reformas en 1885 la torre y la iglesia fueron derribados. Este espacio es actualmente el municipal Museo del Fuego y de los Bomberos. Fuente visual: www.asociacionlossitios.com/', 1875, 1875, 1875, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65367700, -0.88672600, '0101000020E6100000A56950340F60ECBFDE921CB0ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29985184785.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29985184785.webp', 'https://www.flickr.com/photos/zaragozaantigua/29985184785/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24938, 'Monumento a la Madre 1969', 'En 1967, y por suscripciâ”œâ”‚n popular, se erigiâ”œâ”‚ en el parque Primo de Rivera el "Monumento a la Madre", de â”œÃ¼ngel Orensanz, situada en la hondonada cercana a las antiguas piscinas infantiles del acceso al Rincâ”œâ”‚n de Goya (a la izquierda). Este grupo escultâ”œâ”‚rico ha ido sufriendo primero pintadas, y despuâ”œÂ®s la decapitaciâ”œâ”‚n de los dos bultos redondos. Fuente visual: postal Zerkowitz serie "Zaragoza", en www.delcampe.fr/', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63202700, -0.89784200, '0101000020E61000001A355F251FBBECBF3198BF42E6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15675342947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15675342947.webp', 'https://www.flickr.com/photos/zaragozaantigua/15675342947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24428, 'Convento de la Victoria c.1992', 'Imagen capturada en el interior del antiguo patio del convento de La Victoria, reconvertido en sede de los servicios mecâ”œÃ­nicos y talleres municipales e inmediato al parque de bomberos de la calle de Ramâ”œâ”‚n y Cajal. A finales de la dâ”œÂ®cada estos servicios fueron reubicados en otras nuevas instalaciones, y el inmueble fue objeto de una intensa y prolongada rehabilitaciâ”œâ”‚n que en 2012 serâ”œÂ¡a inaugurado como Museo del Fuego. En la imagen, vista del lado norte del antiguo patio, con acceso desde la calle de Ramâ”œâ”‚n Pignatelli.', 1992, 1992, 1992, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65392400, -0.88680200, '0101000020E610000065E08096AE60ECBFE60819C8B3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50218471786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50218471786.webp', 'https://www.flickr.com/photos/zaragozaantigua/50218471786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24547, 'Calle de la Misericordia 1910', 'Dibujo que representa el proyecto del arquitecto Fâ”œÂ®lix Navarro Pâ”œÂ®rez para reformar el Garaje de Automâ”œâ”‚viles Lacarte sito en el nâ”œâ•‘mero 2 de la calle de la Misericordia. actual de la Madre Rafols. Domina en â”œÂ®l la estâ”œÂ®tica modernista que un par de aâ”œâ–’os antes habâ”œÂ¡a dominado la Exposiciâ”œâ”‚n Hispano-Francesa.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65251400, -0.88676200, '0101000020E6100000D8BCAAB35A60ECBF5017299485D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54400948618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54400948618.webp', 'https://www.flickr.com/photos/zaragozaantigua/54400948618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25698, 'Pre-Madre Rafols 1899', 'Mateo Lacarte llevaba metido en el negocio de la construcciâ”œâ”‚n de carruajes desde los aâ”œâ–’os 80 del siglo XIX. Su primer taller estuvo en la calle del 5 de marzo. En 1897 comenzâ”œâ”‚ las gestiones para construir unas nuevas cocheras y talleres de carruajes y de automâ”œâ”‚viles en la calle de Misericordia nâ”¬â•‘ 2, en un solar entre el Cuartel de Pontoneros de Sangenis, y la calle del Hospital . El arquitecto Julio Bravo fue el encargado del proyecto. Tras el â”œÂ®xito de crâ”œÂ¡tica y pâ”œâ•‘blico cosechado por la empresa en la Expo de 1908, estos talleres fueron ampliados con proyecto de Fâ”œÂ®lix Navarro, y en 1928 fueron reformados. En la imagen, publicada en la revista "Aragâ”œâ”‚n Ilustrado", vista de los nuevos talleres y cocheras de la calle de Misericordia. Justo detrâ”œÃ­s, uno de los pabellones del cuartel de Sangenis. A la derecha, fuera de plano, la calle del Hospital. Aâ”œâ–’os despuâ”œÂ®s, estas calles serâ”œÂ¡an redenominadas, respectivamente, "Madre Rafols" y "Ramâ”œâ”‚n y Cajal". Fuente: "Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial en la capital aragonesa entre 1875 y 1936", de Mâ”¬Â¬ P. Biel Ibâ”œÃ­â”œâ–’ez, IFC, 2004.', 1899, 1899, 1899, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65257700, -0.88700600, '0101000020E610000084622B685A62ECBF978FA4A487D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17357775275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17357775275.webp', 'https://www.flickr.com/photos/zaragozaantigua/17357775275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
