INSERT INTO public.photos VALUES (25818, 'Calle Miguel de Ara 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Ara, (Miguel)." Esta es una larga y estrecha calle que une la calle de San Pablo con la de Pignatelli. En la imagen, tramo de la calle Miguel de Ara desde la calle Agustina de Aragâ”œâ”‚n, hasta la de Pignatelli. Al fondo, el Parque de Bomberos ubicado en la esquina entre Pignatelli y Ramâ”œâ”‚n y Cajal.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65429200, -0.88640500, '0101000020E61000002159C0046E5DECBF68041BD7BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14886567489.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14886567489.webp', 'https://www.flickr.com/photos/zaragozaantigua/14886567489/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
